import requests

def get_username(uid):
    resp = requests.get(f"https://api.example.com/users/{uid}")
    return resp.json()["name"].strip().lower()

# test_users.py
class FakeResponse:
    def json(self):
        return {"name": "  Ana  "}

def test_username(monkeypatch):
    monkeypatch.setattr(requests, "get", lambda url: FakeResponse())
    assert get_username(1) == "ana"

import json

def save_config(path, cfg):
    path.write_text(json.dumps(cfg))

def test_save_config(tmp_path):
    file = tmp_path / "settings.json"
    save_config(file, {"theme": "dark"})
    assert json.loads(file.read_text()) == {"theme": "dark"}
